public class ProgramaPrincipal { public static void main(String[] args){ Cachorro cachorro=new Cachorro(); Gato gato=new Gato(); Vaca vaca=new Vaca(); System.out.println(cachorro.somGenerico()+" / "+cachorro.somDoCachorro()); System.out.println(gato.somGenerico()+" / "+gato.somDoGato()); System.out.println(vaca.somGenerico()+" / "+vaca.somDaVaca()); Gerente gerente=new Gerente(5000); Estagiario estagiario=new Estagiario(2000); System.out.println("Gerente: "+gerente.pagamentoComoGerente()); System.out.println("Estagiário: "+estagiario.pagamentoComoEstagiario()); System.out.println(gerente.pagamentoComoGerente()>estagiario.pagamentoComoEstagiario()?"Gerente recebe mais":"Estagiário recebe mais"); Veiculo veiculo=new Veiculo(); Carro carro=new Carro(); Moto moto=new Moto(); System.out.println(veiculo.acelerarGenerico()); System.out.println(carro.acelerarGenerico()+" / "+carro.acelerarCarro()); System.out.println(moto.acelerarGenerico()+" / "+moto.acelerarMoto()); } }
